package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class JsonArrayTest {

  private JsonElement singleElementMock;

  @BeforeEach
  void setUp() {
    singleElementMock = mock(JsonElement.class);
  }

  @Test
  void testGetAsInt_returnsIntFromSingleElement() {
    JsonArray spyArray = new JsonArrayWithOverriddenGetAsSingleElement(singleElementMock);
    JsonArray spy = spy(spyArray);

    when(singleElementMock.getAsInt()).thenReturn(42);

    int result = spy.getAsInt();

    assertEquals(42, result);
    verify(singleElementMock).getAsInt();
  }

  @Test
  void testGetAsInt_throwsIfSingleElementThrows() {
    JsonArray spyArray = new JsonArrayWithOverriddenGetAsSingleElement(singleElementMock);
    JsonArray spy = spy(spyArray);

    when(singleElementMock.getAsInt()).thenThrow(new NumberFormatException("bad number"));

    assertThrows(NumberFormatException.class, spy::getAsInt);
    verify(singleElementMock).getAsInt();
  }

  @Test
  void testGetAsSingleElement_privateMethod_returnsCorrectElement() throws Exception {
    JsonArray jsonArray = new JsonArray();
    JsonElement element = mock(JsonElement.class);
    jsonArray.add(element);

    Method method = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    method.setAccessible(true);

    JsonElement returned = (JsonElement) method.invoke(jsonArray);

    assertSame(element, returned);
  }

  /**
   * Subclass of JsonArray overriding private getAsSingleElement() via reflection.
   */
  private static class JsonArrayWithOverriddenGetAsSingleElement extends JsonArray {
    private final JsonElement overrideElement;

    JsonArrayWithOverriddenGetAsSingleElement(JsonElement overrideElement) {
      this.overrideElement = overrideElement;
    }

    @Override
    @SuppressWarnings("unchecked")
    public int getAsInt() {
      // Override getAsInt to delegate to the overridden getAsSingleElement mock
      return getAsSingleElement().getAsInt();
    }

    // Override getAsSingleElement by reflection hack:
    private JsonElement getAsSingleElement() {
      return overrideElement;
    }
  }
}
